define('taoQtiItem/portableElementRegistry/icRegistry',['lodash', 'taoQtiItem/portableElementRegistry/factory/icRegistry', 'module'], function (_, icRegistry, module) {
  'use strict';
  var registry = icRegistry();
  var providers = [];
  var config = module.config();
  if (config && config.providers) {
    providers = config.providers;
  }
  _.forEach(providers, function (provider) {
    if (provider.name && provider.module) {
      registry.registerProvider(provider.module);
    }
  });
  return registry;
});
